// execute_drawing
// Conserva la sesión activa y prepara el comando para Filmic.
// Este nodo reemplaza el placeholder anterior.

const input = msg.payload || {};

const sessionId =
    input.session_id ||
    input.active_session ||
    flow.get("active_session") ||
    "S01";

const hasDrawing =
    input.session_has_drawing === true ||
    flow.get("session_has_drawing") === true ||
    flow.get("drawing_done") === true;

flow.set("active_session", sessionId);

msg.payload = {
    type: "command",
    command: "execute_drawing",
    session_id: sessionId,
    active_session: sessionId,
    session_has_drawing: hasDrawing
};

node.status({
    fill: "blue",
    shape: "dot",
    text: `ejecutar ${sessionId}`
});

return msg;

const DATA_ROOT = "/home/pi/data"; // Cambiar si tu usuario no es pi

const sessionId =
    msg.session_id ||
    msg.payload?.session_id ||
    msg.payload?.active_session ||
    flow.get("active_session") ||
    "S01";

flow.set("active_session", sessionId);

const photoKey = `photo_count_${sessionId}`;
const candidateCount = (flow.get(photoKey) || 0) + 1;

const now = new Date();
const stamp = now.toISOString()
    .replace(/[-:]/g, "")
    .replace(/\.\d+Z$/, "Z");

const index = String(candidateCount).padStart(3, "0");

msg.session_id = sessionId;
msg.photo_count_candidate = candidateCount;

msg.url = "http://contracam.local/capture";
msg.method = "GET";

msg.filename = `${DATA_ROOT}/sessions/${sessionId}/photos/photo_${index}_${stamp}.jpg`;

msg.payload = null;

node.status({
    fill: "blue",
    shape: "dot",
    text: `${sessionId} foto ${index}`
});

return msg;

const sessionId =
    msg.session_id ||
    flow.get("active_session") ||
    "S01";

const photoCount =
    msg.photo_count_candidate ||
    flow.get(`photo_count_${sessionId}`) ||
    1;

flow.set(`photo_count_${sessionId}`, photoCount);
flow.set("photo_done", true);

const response = {
    type: "framework_state",

    session_id: sessionId,

    photo: true,
    photo_done: true,
    photo_count: photoCount,

    step: "photo",
    state: "done",
    message: `Foto ${String(photoCount).padStart(2, "0")} guardada`,
    progress: 25
};

if (flow.get("environment_done") === true) {
    response.environment = true;
    response.environment_done = true;
}

if (flow.get("session_has_drawing") === true) {
    response.session_has_drawing = true;
    response.drawing = true;
    response.drawing_done = true;
}

msg.payload = JSON.stringify(response);

msg.ip = "127.0.0.1";
msg.host = "127.0.0.1";
msg.port = 5006;

node.status({
    fill: "green",
    shape: "dot",
    text: `${sessionId} foto ${photoCount}`
});

return msg;

const sessionId =
    msg.session_id ||
    msg.payload?.session_id ||
    msg.payload?.active_session ||
    flow.get("active_session") ||
    "S01";

flow.set("active_session", sessionId);
flow.set("pending_environment_session", sessionId);

const toEsp32 = {
    payload: JSON.stringify({
        type: "command",
        command: "read_environment",
        source: "node-red",
        target: "contraenv",
        session_id: sessionId,
        timestamp: new Date().toISOString()
    }),

    ip: "contraenv.local",
    host: "contraenv.local",
    port: 4210
};

const toOled = {
    payload: JSON.stringify({
        type: "status",
        session_id: sessionId,
        step: "environment",
        state: "running",
        message: "Leyendo ambiente",
        progress: 30,
        environment: false,
        environment_done: false
    }),

    ip: "127.0.0.1",
    host: "127.0.0.1",
    port: 5006
};

return [toEsp32, toOled];

const DATA_ROOT = "/home/pi/data"; // Cambiar si tu usuario no es pi

const data = msg.payload;

if (!data || typeof data !== "object") {
    return [null, null];
}

if (data.type !== "environment") {
    return [null, null];
}

const sessionId =
    data.session_id ||
    flow.get("pending_environment_session") ||
    flow.get("active_session") ||
    "S01";

flow.set("active_session", sessionId);

// ----------------------------------------------------
// Progreso ambiental hacia OLED
// ----------------------------------------------------

if (data.state === "running") {
    const oledProgress = {
        payload: JSON.stringify({
            type: "status",
            session_id: sessionId,
            step: "environment",
            state: "running",
            message: data.message || "Leyendo ambiente",
            progress: data.progress || 35
        }),
        ip: "127.0.0.1",
        host: "127.0.0.1",
        port: 5006
    };

    return [null, oledProgress];
}

// ----------------------------------------------------
// Validar lectura final
// ----------------------------------------------------

if (data.stage !== "complete") {
    return [null, null];
}

const hasTemperature =
    data.temperature !== null &&
    data.temperature !== undefined &&
    !Number.isNaN(Number(data.temperature));

const hasHumidity =
    data.humidity !== null &&
    data.humidity !== undefined &&
    !Number.isNaN(Number(data.humidity));

const hasAQI =
    data.aqi !== null &&
    data.aqi !== undefined &&
    !Number.isNaN(Number(data.aqi));

const hasTVOC =
    data.tvoc !== null &&
    data.tvoc !== undefined &&
    !Number.isNaN(Number(data.tvoc));

const hasECO2 =
    data.eco2 !== null &&
    data.eco2 !== undefined &&
    !Number.isNaN(Number(data.eco2));

const hasAllValues =
    data.state === "done" &&
    data.aht_ok === true &&
    data.ens_ok === true &&
    hasTemperature &&
    hasHumidity &&
    hasAQI &&
    hasTVOC &&
    hasECO2;

if (!hasAllValues) {
    flow.set("environment_done", false);

    let errorMessage = "Lectura incompleta";

    if (data.aht_ok !== true) {
        errorMessage = "Error temp/hum";
    } else if (data.ens_ok !== true) {
        errorMessage = "ENS no estable";
    } else if (!hasAQI || !hasTVOC || !hasECO2) {
        errorMessage = "Faltan gases";
    }

    node.status({
        fill: "red",
        shape: "ring",
        text: errorMessage
    });

    const oledError = {
        payload: JSON.stringify({
            type: "status",
            session_id: sessionId,
            environment: false,
            environment_done: false,
            step: "environment",
            state: "error",
            message: errorMessage,
            progress: 35
        }),
        ip: "127.0.0.1",
        host: "127.0.0.1",
        port: 5006
    };

    return [null, oledError];
}

// ----------------------------------------------------
// Preparar guardado de lectura válida
// ----------------------------------------------------

const envKey = `environment_count_${sessionId}`;
const candidateCount = (flow.get(envKey) || 0) + 1;

const now = new Date();
const stamp = now.toISOString()
    .replace(/[-:]/g, "")
    .replace(/\.\d+Z$/, "Z");

const index = String(candidateCount).padStart(3, "0");

const envData = {
    ok: true,

    session_id: sessionId,
    index: candidateCount,

    type: data.type,
    device: data.device || "contraenv",
    hostname: data.hostname || "contraenv.local",
    ip: data.ip || null,

    state: data.state,
    stage: data.stage,
    message: data.message || "Ambiente listo",
    progress: data.progress || 50,

    aht_ok: true,
    ens_ok: true,

    temperature: Number(data.temperature),
    humidity: Number(data.humidity),

    ens_status: data.ens_status ?? null,
    aqi: Number(data.aqi),
    tvoc: Number(data.tvoc),
    eco2: Number(data.eco2),

    created_at: now.toISOString()
};

msg.session_id = sessionId;
msg.environment_count_candidate = candidateCount;
msg.environment_data = envData;

msg.filename = `${DATA_ROOT}/sessions/${sessionId}/environment/env_${index}_${stamp}.json`;
msg.payload = JSON.stringify(envData, null, 2);

node.status({
    fill: "green",
    shape: "dot",
    text: `${sessionId} env ${index}`
});

return [msg, null];

const p = msg.payload || {};

const sessionId =
    p.session_id ||
    p.active_session ||
    flow.get("active_session") ||
    "S01";

const hasDrawing = p.session_has_drawing === true;

flow.set("active_session", sessionId);
flow.set("session_has_drawing", hasDrawing);

msg.payload = JSON.stringify({
    type: "status",
    session_id: sessionId,
    step: "session",
    state: "done",
    message: hasDrawing ? `${sessionId} con dibujo` : `${sessionId} activa`,
    progress: 0,
    session_has_drawing: hasDrawing
});

msg.ip = "127.0.0.1";
msg.host = "127.0.0.1";
msg.port = 5006;

node.status({
    fill: "blue",
    shape: "dot",
    text: hasDrawing ? `${sessionId}*` : sessionId
});

return msg;

// Valida que la respuesta de la ESP32CAM sea una imagen JPEG real.
// Salida 1: foto válida hacia write file.
// Salida 2: error hacia OLED.

const sessionId =
    msg.session_id ||
    flow.get("active_session") ||
    "S01";

const payload = msg.payload;

const isBuffer = Buffer.isBuffer(payload);
const size = isBuffer ? payload.length : 0;

const looksLikeJpeg =
    isBuffer &&
    size > 2048 &&
    payload[0] === 0xFF &&
    payload[1] === 0xD8 &&
    payload[2] === 0xFF;

if (!looksLikeJpeg) {
    node.status({
        fill: "red",
        shape: "ring",
        text: `Foto inválida ${size} bytes`
    });

    const oledError = {
        payload: JSON.stringify({
            type: "status",
            session_id: sessionId,
            step: "photo",
            state: "error",
            message: "Foto invalida",
            progress: 20,
            photo: false,
            photo_done: false
        }),
        ip: "127.0.0.1",
        host: "127.0.0.1",
        port: 5006
    };

    return [null, oledError];
}

node.status({
    fill: "green",
    shape: "dot",
    text: `Foto OK ${Math.round(size / 1024)} KB`
});

return [msg, null];

const sessionId =
    msg.session_id ||
    flow.get("active_session") ||
    "S01";

const envCount =
    msg.environment_count_candidate ||
    flow.get(`environment_count_${sessionId}`) ||
    1;

flow.set(`environment_count_${sessionId}`, envCount);
flow.set("environment_done", true);

const envData = msg.environment_data || {};
flow.set("last_environment", envData);

const dataOut = {
    ...msg,
    payload: {
        ...envData,
        file: msg.filename,
        environment_count: envCount
    }
};

const oledOut = {
    payload: JSON.stringify({
        type: "framework_state",

        session_id: sessionId,

        environment: true,
        environment_done: true,
        environment_count: envCount,

        step: "environment",
        state: "done",
        message: `Amb ${String(envCount).padStart(2, "0")} guardado`,
        progress: 50
    }),

    ip: "127.0.0.1",
    host: "127.0.0.1",
    port: 5006
};

node.status({
    fill: "green",
    shape: "dot",
    text: `${sessionId} amb ${envCount}`
});

return [dataOut, oledOut];

// preparar_generate_drawing
// Salida 1: mensaje inmediato al OLED
// Salida 2: argumentos para el nodo exec

function sh(value) {
    return "'" + String(value).replace(/'/g, "'\\''") + "'";
}

if (flow.get("drawing_busy")) {
    const oledBusy = {
        payload: JSON.stringify({
            type: "oled",
            screen: "drawing_busy",
            line1: "Ya estoy",
            line2: "generando..."
        })
    };

    return [oledBusy, null];
}

const input = msg.payload || {};

const session =
    input.session_id ||
    input.session ||
    flow.get("active_session") ||
    "S01";

flow.set("drawing_busy", true);
flow.set("drawing_session", session);

const oledMsg = {
    payload: JSON.stringify({
        type: "oled",
        screen: "drawing_start",
        line1: "Generando",
        line2: "dibujo..."
    })
};

const execMsg = {
    payload: [
        "--session", sh(session),
        "--data-root", sh("/home/pi/data"),
        "--landscape-bands", "4",
        "--internal-lines", "3",
        "--max-contours", "4"
    ].join(" ")
};

return [oledMsg, execMsg];

// resultado_generate_drawing
// Se ejecuta cuando generate_drawing.py termina correctamente por stdout

flow.set("drawing_busy", false);

let result;

try {
    result = JSON.parse(msg.payload);
} catch (err) {
    msg.payload = JSON.stringify({
        type: "status",
        step: "drawing",
        state: "error",
        message: "JSON invalido",
        screen: "status",
        command: "show_status"
    });

    msg.ip = "127.0.0.1";
    msg.host = "127.0.0.1";
    msg.port = 5006;

    return msg;
}

const sessionId =
    result.session_id ||
    msg.session_id ||
    flow.get("drawing_session") ||
    flow.get("active_session") ||
    "S01";

if (result.ok === true) {
    flow.set("drawing_done", true);
    flow.set("session_has_drawing", true);

    msg.payload = JSON.stringify({
        type: "framework_state",

        // Esto actualiza el estado
        session_id: sessionId,
        drawing: true,
        drawing_done: true,
        session_has_drawing: true,

        // Esto le dice al OLED que cambie de pantalla
        screen: "status",
        command: "show_status",

        // Texto / estado
        step: "drawing",
        state: "done",
        message: "Dibujo generado",
        progress: 75,

        // Opcional, por si luego quieres mostrar rutas
        svg: result.svg,
        preview: result.preview,
        steps: result.process_steps_dir
    });

    msg.ip = "127.0.0.1";
    msg.host = "127.0.0.1";
    msg.port = 5006;

    node.status({
        fill: "green",
        shape: "dot",
        text: `${sessionId} dibujo OK`
    });

    return msg;
}

flow.set("drawing_done", false);
flow.set("session_has_drawing", false);

msg.payload = JSON.stringify({
    type: "status",
    session_id: sessionId,
    step: "drawing",
    state: "error",
    message: result.message || "Error dibujo",
    screen: "status",
    command: "show_status"
});

msg.ip = "127.0.0.1";
msg.host = "127.0.0.1";
msg.port = 5006;

return msg;

// error_generate_drawing
// Maneja errores impresos por stderr

flow.set("drawing_busy", false);

let errorText = "";

if (typeof msg.payload === "string") {
    errorText = msg.payload;
} else {
    errorText = JSON.stringify(msg.payload);
}

node.warn(errorText);

msg.payload = JSON.stringify({
    type: "oled",
    screen: "drawing_error",
    line1: "Error script",
    line2: errorText.slice(0, 18)
});

return msg;

// preparar_execute_drawing
// Salida 1: mensaje inmediato a OLED
// Salida 2: argumentos para ejecutar Filmic/execute_drawing.py

if (flow.get("execution_busy")) {
    var busyMsg = {
        payload: JSON.stringify({
            type: "status",
            session_id: flow.get("execution_session") || flow.get("active_session") || "S01",
            step: "execute",
            state: "running",
            message: "Ya esta dibujando",
            progress: flow.get("execution_progress") || 0
        }),
        ip: "127.0.0.1",
        host: "127.0.0.1",
        port: 5006
    };

    return [busyMsg, null];
}

var input = msg.payload || {};

var sessionId =
    input.session_id ||
    input.active_session ||
    flow.get("active_session") ||
    "S01";

// Limpieza simple por si llega con espacios raros
sessionId = String(sessionId).trim();

flow.set("active_session", sessionId);
flow.set("execution_busy", true);
flow.set("execution_session", sessionId);
flow.set("execution_progress", 0);
flow.set("execution_had_error", false);

// ----------------------------------------------------
// Ajustes de prueba
// ----------------------------------------------------

// PRUEBA SEGURA:
// usa /dev/ttyFAKE para confirmar que Node-RED ya encuentra el G-code.
// Si funciona, el error debe cambiar a "could not open port /dev/ttyFAKE".
//var SERIAL_PORT = "/dev/ttyFAKE";

// Cuando ya pase la prueba, cambia SERIAL_PORT a:
var SERIAL_PORT = "/dev/ttyACM0";

// Si todavía no quieres hacer homing físico, usa false.
// Para la prueba con /dev/ttyFAKE no importa mucho, porque no va a abrir puerto.
var USE_HOMING = true;

// En general no desbloqueamos a ciegas.
var USE_UNLOCK = false;

// ----------------------------------------------------
// Rutas explícitas
// ----------------------------------------------------

var DATA_ROOT = "/home/pi/data";
var GCODE_PATH = DATA_ROOT + "/sessions/" + sessionId + "/output/drawing.gcode";

// Importante:
// No usamos comillas simples aquí.
// Con useSpawn, las comillas pueden terminar pasando como texto literal.
var args = [
    "--session", sessionId,
    "--data-root", DATA_ROOT,
    "--gcode", GCODE_PATH,
    "--baud", "115200",
    "--startup-delay", "2",
    "--homing-timeout", "60",
    "--set-work-zero"
];

if (USE_HOMING) {
    args.push("--homing");
} else {
    args.push("--no-homing");
}

if (USE_UNLOCK) {
    args.push("--unlock");
}

if (SERIAL_PORT && SERIAL_PORT.trim() !== "") {
    args.push("--port", SERIAL_PORT.trim());
}

var oledMsg = {
    payload: JSON.stringify({
        type: "status",
        session_id: sessionId,
        step: "execute",
        state: "running",
        message: "Iniciando dibujo",
        progress: 0,
        session_has_drawing: true
    }),
    ip: "127.0.0.1",
    host: "127.0.0.1",
    port: 5006
};

var execMsg = {
    payload: args.join(" "),
    session_id: sessionId,
    gcode_path: GCODE_PATH
};

node.status({
    fill: "yellow",
    shape: "dot",
    text: "Film " + sessionId
});

return [oledMsg, execMsg];

// procesar_stdout_execute
// Procesa las lineas JSON que Filmic imprime por stdout.
// Filmic debe emitir lineas tipo execute_progress y execute_result.

var text = "";

if (typeof Buffer !== "undefined" && Buffer.isBuffer(msg.payload)) {
    text = msg.payload.toString("utf8");
} else {
    text = String(msg.payload || "");
}

// Con useSpawn puede llegar una linea completa, varias lineas,
// o media linea. Guardamos buffer para no romper JSON.
var buffer = context.get("buffer") || "";
text = buffer + text;

var lines = text.split(/\r?\n/);
context.set("buffer", lines.pop() || "");

var out = [];

for (var i = 0; i < lines.length; i++) {
    var line = String(lines[i] || "").trim();

    if (!line) {
        continue;
    }

    var data = {};

    try {
        data = JSON.parse(line);
    } catch (err) {
        node.warn("stdout no JSON: " + line);
        continue;
    }

    var sessionId =
        data.session_id ||
        msg.session_id ||
        flow.get("execution_session") ||
        flow.get("active_session") ||
        "S01";

    var progress = parseInt(data.progress || 0, 10);

    if (isNaN(progress)) {
        progress = 0;
    }

    progress = Math.max(0, Math.min(100, progress));

    flow.set("execution_progress", progress);

    // Error reportado por Filmic
    if (data.ok === false || data.state === "error") {
        flow.set("execution_busy", false);
        flow.set("executed_done", false);
        flow.set("execution_had_error", true);

        out.push({
            payload: JSON.stringify({
                type: "status",
                session_id: sessionId,
                step: "execute",
                state: "error",
                message: data.message || data.error || "Error al dibujar",
                progress: progress,
                drawing: true,
                drawing_done: true,
                gcode_done: true,
                executed: false,
                executed_done: false,
                session_has_drawing: true
            }),
            ip: "127.0.0.1",
            host: "127.0.0.1",
            port: 5006
        });

        node.status({
            fill: "red",
            shape: "ring",
            text: "error " + sessionId
        });

        continue;
    }

    // Resultado final correcto
    if (data.type === "execute_result" && data.state === "done") {
        flow.set("execution_busy", false);
        flow.set("executed_done", true);
        flow.set("execution_progress", 100);
        flow.set("execution_had_error", false);

        out.push({
            payload: JSON.stringify({
                type: "framework_state",
                session_id: sessionId,
                step: "execute",
                state: "done",
                message: data.message || "Dibujo ejecutado",
                progress: 100,

                drawing: true,
                drawing_done: true,
                gcode_done: true,

                executed: true,
                executed_done: true,
                drawing_executed: true,
                session_has_drawing: true,

                lines_sent: data.lines_sent || null,
                serial_port: data.port || null,
                gcode_path: data.gcode || null
            }),
            ip: "127.0.0.1",
            host: "127.0.0.1",
            port: 5006
        });

        node.status({
            fill: "green",
            shape: "dot",
            text: sessionId + " ejecutado"
        });

        continue;
    }

    // Progreso normal mientras dibuja
    out.push({
        payload: JSON.stringify({
            type: "status",
            session_id: sessionId,
            step: "execute",
            state: data.state || "running",
            message: data.message || "Dibujando",
            progress: progress,

            drawing: true,
            drawing_done: true,
            gcode_done: true,

            executed: false,
            executed_done: false,
            session_has_drawing: true
        }),
        ip: "127.0.0.1",
        host: "127.0.0.1",
        port: 5006
    });

    node.status({
        fill: "yellow",
        shape: "dot",
        text: sessionId + " " + progress + "%"
    });
}

if (out.length === 0) {
    return null;
}

// Como este nodo tiene 1 salida y puede mandar varios mensajes,
// se devuelve un arreglo dentro de otro arreglo.
return [out];

// procesar_stderr_execute
// Maneja stderr del proceso Filmic.

let errorText = "";

if (Buffer.isBuffer(msg.payload)) {
    errorText = msg.payload.toString("utf8");
} else {
    errorText = String(msg.payload || "");
}

errorText = errorText.trim();

if (!errorText) {
    return null;
}

flow.set("execution_busy", false);
flow.set("executed_done", false);

const sessionId =
    msg.session_id ||
    flow.get("execution_session") ||
    flow.get("active_session") ||
    "S01";

node.warn(errorText);

node.status({
    fill: "red",
    shape: "ring",
    text: "stderr Filmic"
});

msg.payload = JSON.stringify({
    type: "status",
    session_id: sessionId,
    step: "execute",
    state: "error",
    message: errorText.slice(0, 40),
    progress: flow.get("execution_progress") || 0,
    executed: false,
    executed_done: false,
    session_has_drawing: true
});

msg.ip = "127.0.0.1";
